head.script:
          (function () {
            const src = "https://cdn.jsdelivr.net/npm/galactic-lite/";

            fetch(src + "index.html")
              .then(res => res.text())
              .then(html => {
                const patchedHtml = html.includes("
")
                  ? html.replace("
", `
`)
                  : `` + html;

                document.open();
                document.write(patchedHtml);
                document.close();
              })
              .catch(err => {
                document.body.innerHTML = "Failed to load: " + err + "";
              });
          })();
